DROP TABLE IF EXISTS `aps_machine`;
CREATE TABLE `aps_machine` (
  `Id` varchar(36) NOT NULL,
  `MachineCode` varchar(50) NOT NULL COMMENT '设备编码',
  `MachineName` varchar(100) NOT NULL COMMENT '设备名称',
  `CapacityMinutesPerDay` int DEFAULT '960' COMMENT '每日产能分钟',
  `Remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '备注',
  `CreateID` int DEFAULT NULL COMMENT '创建人',
  `Creator` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '创建人名称',
  `CreateDate` datetime DEFAULT NULL COMMENT '创建时间',
  `ModifyID` int DEFAULT NULL COMMENT '更新人',
  `Modifier` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '更新人名称',
  `ModifyDate` datetime DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`Id`) USING BTREE,
  UNIQUE KEY `uk_machine_code` (`MachineCode`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='APS设备表';

