-- Table structure for table aps_schedule_result
-- ----------------------------
DROP TABLE IF EXISTS `aps_schedule_result`;
CREATE TABLE `aps_schedule_result` (
  `Id` varchar(36) NOT NULL COMMENT '主键GUID',
  `WorkOrderId` varchar(36) NOT NULL COMMENT '工单ID',
  `WorkOrderNo` varchar(50) NOT NULL COMMENT '工单号',
  `MachineCode` varchar(50) NOT NULL COMMENT '设备编码',
  `MachineName` varchar(100) DEFAULT NULL COMMENT '设备名称',
  `PlanStartTime` datetime NOT NULL COMMENT '计划开始时间',
  `PlanEndTime` datetime NOT NULL COMMENT '计划结束时间',
  `PlanMinutes` int NOT NULL COMMENT '计划生产分钟数',
  `OrderQty` decimal(18,2) NOT NULL COMMENT '订单数量',
  `CustomerName` varchar(100) DEFAULT NULL COMMENT '客户',
  `CustomerPriority` int DEFAULT NULL COMMENT '客户优先级',
  `EarliestStartTime` datetime DEFAULT NULL COMMENT '工单最早开始时间',
  `LatestDeliveryDate` datetime DEFAULT NULL COMMENT '工单最晚交付日期',
  `IsDelay` tinyint DEFAULT '0' COMMENT '是否延期：0否，1是',
  `DelayMinutes` int DEFAULT '0' COMMENT '延期分钟数',
  `ScheduleStatus` varchar(20) DEFAULT '已排产' COMMENT '排产状态',
  `Remark` varchar(500) DEFAULT NULL COMMENT '备注',
  `CreateID` int DEFAULT NULL COMMENT '创建人',
  `Creator` varchar(50) DEFAULT NULL COMMENT '创建人名称',
  `CreateDate` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `ModifyID` int DEFAULT NULL COMMENT '更新人',
  `Modifier` varchar(50) DEFAULT NULL COMMENT '更新人名称',
  `ModifyDate` datetime DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`Id`) USING BTREE,
  KEY `idx_work_order_id` (`WorkOrderId`),
  KEY `idx_work_order_no` (`WorkOrderNo`),
  KEY `idx_machine_code` (`MachineCode`),
  KEY `idx_plan_time` (`PlanStartTime`,`PlanEndTime`),
  KEY `idx_delay` (`IsDelay`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='APS排产结果表';

