-- Table structure for table aps_schedule_time
-- ----------------------------
DROP TABLE IF EXISTS `aps_schedule_time`;
CREATE TABLE `aps_schedule_time` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `schedule_date` date NOT NULL COMMENT '排产日期',
  `line_code` varchar(50) NOT NULL COMMENT '产线编码',
  `line_name` varchar(100) DEFAULT NULL COMMENT '产线名称',
  `shift_id` bigint NOT NULL COMMENT '班次ID',
  `shift_code` varchar(50) NOT NULL COMMENT '班次编码',
  `shift_name` varchar(100) NOT NULL COMMENT '班次名称',
  `start_datetime` datetime NOT NULL COMMENT '开始时间',
  `end_datetime` datetime NOT NULL COMMENT '结束时间',
  `available_minutes` int NOT NULL COMMENT '可用分钟数',
  `used_minutes` int NOT NULL DEFAULT '0' COMMENT '已使用分钟数',
  `remain_minutes` int NOT NULL COMMENT '剩余分钟数',
  `status` tinyint NOT NULL DEFAULT '1' COMMENT '状态：1可用，2停机，3维护，4休息',
  `enable_flag` tinyint NOT NULL DEFAULT '1' COMMENT '是否启用：0否，1是',
  `remark` varchar(500) DEFAULT NULL COMMENT '备注',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `line_id` int DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_schedule_date` (`schedule_date`),
  KEY `idx_line_code` (`line_code`),
  KEY `idx_shift_id` (`shift_id`),
  KEY `idx_start_end_time` (`start_datetime`,`end_datetime`),
  CONSTRAINT `fk_aps_schedule_time_shift` FOREIGN KEY (`shift_id`) REFERENCES `aps_shift` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=442135411167325 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='排产时间表';

