  `work_minutes` int NOT NULL COMMENT '工作分钟数',
  `enable_flag` tinyint NOT NULL DEFAULT '1' COMMENT '是否启用：0否，1是',
  `remark` varchar(500) DEFAULT NULL COMMENT '备注',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_aps_shift_code` (`shift_code`)
) ENGINE=InnoDB AUTO_INCREMENT=439625834147910 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='排产班次表';

